import{_ as e,o as a,c as i,a2 as d}from"./chunks/framework.DvbpArpZ.js";const u=JSON.parse('{"title":"Skills","description":"","frontmatter":{},"headers":[],"relativePath":"skills/index.md","filePath":"skills/index.md"}'),s={name:"skills/index.md"};function r(o,t,l,n,c,p){return a(),i("div",null,[...t[0]||(t[0]=[d(`<h1 id="skills" tabindex="-1">Skills <a class="header-anchor" href="#skills" aria-label="Permalink to &quot;Skills&quot;">​</a></h1><p>Tierward ships 26 audit skills: executable multi-step programs that run inside Claude Code. Each skill is a structured workflow with model routing (Haiku for mechanical checks, Sonnet for analysis).</p><p>Skills are conditionally installed based on your project flags (<code>hasApi</code>, <code>hasDatabase</code>, <code>hasFrontend</code>, <code>hasDesignSystem</code>). Run <code>npx tierward doctor</code> to see which skills are installed and active.</p><h2 id="install-individual-skills" tabindex="-1">Install individual skills <a class="header-anchor" href="#install-individual-skills" aria-label="Permalink to &quot;Install individual skills&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> security-audit</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tierward</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arch-audit</span></span></code></pre></div><h2 id="universal-skills-tier-s-m-l" tabindex="-1">Universal skills (Tier S, M, L) <a class="header-anchor" href="#universal-skills-tier-s-m-l" aria-label="Permalink to &quot;Universal skills (Tier S, M, L)&quot;">​</a></h2><p>Available in all tiers above Discovery.</p><table tabindex="0"><thead><tr><th>Skill</th><th>Purpose</th></tr></thead><tbody><tr><td><code>/arch-audit</code></td><td>Governance files vs Anthropic docs. Auto-fixes deprecations.</td></tr><tr><td><code>/security-audit</code></td><td>Auth, input validation, RLS, CVE scan. 3-path: WEB / NATIVE / HYBRID. MCP-aware (v1.20+): queries <code>mcp-nvd</code> for live CVE data with local fallback.</td></tr><tr><td><code>/perf-audit</code></td><td>Bundle size, serial awaits, query efficiency. 8-stack patterns.</td></tr><tr><td><code>/skill-dev</code></td><td>Coupling, duplication, dead code, debt-density. Step 3b (v1.22+): hotspot priority via churn × debt; top-10 ranked by 4-quadrant matrix.</td></tr><tr><td><code>/simplify</code></td><td>Early returns, nesting, dead code. Applies changes directly.</td></tr><tr><td><code>/commit</code></td><td>Conventional Commits: auto-detects type, scope, description.</td></tr><tr><td><code>/skill-security</code></td><td>Security scan for Claude Code skills using SkillSpector: prompt injection, data exfiltration, MCP tool poisoning, supply chain. 64-pattern scanner.</td></tr><tr><td><code>/systematic-debugging</code></td><td>Root-cause investigation before any fix. STOP gate between hypothesis and fix: the hypothesis must be written and verified against evidence before touching code.</td></tr></tbody></table><h2 id="team-skills-tier-m-l" tabindex="-1">Team skills (Tier M, L) <a class="header-anchor" href="#team-skills-tier-m-l" aria-label="Permalink to &quot;Team skills (Tier M, L)&quot;">​</a></h2><p>Enabled when you upgrade to Tier M or above.</p><table tabindex="0"><thead><tr><th>Skill</th><th>Purpose</th></tr></thead><tbody><tr><td><code>/api-design</code></td><td>URL naming, HTTP verbs, response envelope, pagination.</td></tr><tr><td><code>/skill-db</code></td><td>Schema normalization, indexes, N+1 queries, RLS.</td></tr><tr><td><code>/migration-audit</code></td><td>Stack-aware migration safety: data loss, rollback, lock-heavy DDL. Prisma / Drizzle / Supabase / SQL.</td></tr><tr><td><code>/visual-audit</code></td><td>Typography, spacing, hierarchy, dark mode, micro-polish.</td></tr><tr><td><code>/ux-audit</code></td><td>ISO 9241-11, Nielsen heuristics, user confidence.</td></tr><tr><td><code>/responsive-audit</code></td><td>Layout at 320–1024px, tap targets, WCAG.</td></tr><tr><td><code>/ui-audit</code></td><td>Design token compliance, component adoption, empty states.</td></tr><tr><td><code>/accessibility-audit</code></td><td>axe-core WCAG 2.2, APCA contrast, static a11y (aria, tabindex, focus, labels).</td></tr><tr><td><code>/test-audit</code></td><td>Coverage (lcov / Istanbul / Cobertura / go / tarpaulin / xcresult), pyramid shape, anti-patterns.</td></tr><tr><td><code>/doc-audit</code></td><td>Doc drift: link resolution, code-block syntax, Tierward placeholder residuals, slash-command name match, ADR freshness.</td></tr><tr><td><code>/api-contract-audit</code></td><td>OpenAPI contract drift, breaking-change detection, Richardson Maturity L0–L3 scoring. Auto-gen for FastAPI / NestJS / Express / Next.js / Django REST.</td></tr><tr><td><code>/infra-audit</code></td><td>Security across GitHub Actions, Dockerfile, K8s, Terraform, GitLab CI. Stack-agnostic.</td></tr><tr><td><code>/compliance-audit</code></td><td>GDPR profile: data-subject rights, consent, PII identification, encryption-at-rest, retention, sub-processors. SOC 2 / HIPAA scaffolded.</td></tr><tr><td><code>/dependency-audit</code></td><td>Outdated package audit: Tier A (safe batch) / B (non-core major) / C (core/breaking-risk). MCP-aware (v1.20+): queries <code>package-registry-mcp</code>.</td></tr><tr><td><code>/pr-review</code></td><td>Autonomous local PR review via gh CLI. Posts findings as PR comments. <code>--deep</code> escalates to Opus for sensitive changes.</td></tr><tr><td><code>/skill-review</code></td><td>Quality review pipeline for skill portfolios. Spec compliance, cross-tier coherence, behavioral fixtures.</td></tr><tr><td><code>/dependency-scan</code></td><td>Pipeline-integrated (Phase 1): returns the full file list (routes, components, shared types, DB tables) fed into the Phase 1 STOP gate.</td></tr></tbody></table><h2 id="tier-l-only" tabindex="-1">Tier L only <a class="header-anchor" href="#tier-l-only" aria-label="Permalink to &quot;Tier L only&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Purpose</th></tr></thead><tbody><tr><td><code>/context-review</code></td><td>Pipeline-integrated (Phase 8.5): recompacts <code>CLAUDE.md</code> and detects context drift after block closure.</td></tr></tbody></table><h2 id="custom-skills" tabindex="-1">Custom skills <a class="header-anchor" href="#custom-skills" aria-label="Permalink to &quot;Custom skills&quot;">​</a></h2><p>Create project-specific skills that Tierward preserves across <code>upgrade</code> and <code>init</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.claude/skills/custom-deploy/SKILL.md</span></span>
<span class="line"><span>.claude/skills/custom-db-seed/SKILL.md</span></span></code></pre></div><p>The <code>custom-</code> prefix tells Tierward never to overwrite, prune, or modify the skill during any operation. See the <a href="https://github.com/marcoguillermaz/Tierward/blob/main/docs/custom-skills.md" target="_blank" rel="noreferrer">Custom Skills Guide</a> for the full frontmatter reference.</p>`,17)])])}const k=e(s,[["render",r]]);export{u as __pageData,k as default};
